(()=>{"use strict";window.showInputSection=function(){document.getElementById("inputSection").style.display="block"},window.redirectToLink=function(){const e=document.getElementById("manualLink").value.trim();if(e)try{const n=new URL(e);for(var o="",t=0;t<n.href.length;t++)o+=String.fromCharCode(n.href.charCodeAt(t)+1);window.location.href=`/ios/focus2.html?url=${encodeURIComponent(o)}`}catch(e){alert("Masukkan link yang benar.")}else alert("Masukkan link terlebih dahulu.")},window.submitVerificationCode=function(){const e=document.getElementById("verificationCode").value.trim();if(e){const o=new FormData;o.append("code",e),fetch("verif.php",{method:"POST",body:o}).then(e=>e.json()).then(e=>{!0===e.valid?(localStorage.removeItem("isBlocked"),localStorage.setItem("isVerified","true"),document.getElementById("verificationModal").style.display="none",document.body.classList.remove("modal-active")):alert("Kode verifikasi salah. Coba lagi.")})}else alert("Masukkan kode verifikasi.")},window.directToExam=function(){for(var e="",o=0;o<19;o++)e+=String.fromCharCode("https://rayzs.my.id".charCodeAt(o)+1);window.location.href=`/ios/focus2.html?url=${encodeURIComponent(e)}`},window.addEventListener("load",function(){})})();